import json
import pathlib
import subprocess

import pytest

AC_UID = "ac07_unspaced_separator_matrix_v2"
AC_TYPE = "hook"

REPO_ROOT = pathlib.Path(__file__).resolve().parents[3]
HOOK_PATH = REPO_ROOT / "hooks" / "pretool-bash-safety.sh"
STABLE_STDERR_TOKEN = "bulk-commit-auth-flag-write"

_FLAG = "/tmp/claude-bulk-allowed-testsid.flag"


def _run_hook_with_payload(hook_path, command):
    payload = {
        "tool_name": "Bash",
        "agent_id": "qa-test",
        "tool_input": {"command": command},
    }
    proc = subprocess.run(
        ["bash", str(hook_path)],
        input=json.dumps(payload),
        capture_output=True,
        text=True,
        timeout=10,
    )
    return proc.returncode, proc.stdout, proc.stderr


MATRIX = [
    ("a_unspaced_semi",
     f"ls {_FLAG};python3 -c 'open(\"/tmp/x\",\"w\")'", 2),
    ("b_unspaced_andand",
     f"ls {_FLAG}&&touch /tmp/x", 2),
    ("c_unspaced_oror",
     f"ls {_FLAG}||touch /tmp/x", 2),
    ("d_unspaced_pipe",
     f"cat {_FLAG}|cat", 2),
]


@pytest.mark.parametrize(
    "case,command,expected_exit",
    MATRIX,
    ids=[row[0] for row in MATRIX],
)
def test_AC_07_unspaced_separator_matrix(case, command, expected_exit):
    """
    GIVEN: compound commands with no whitespace around the shell separator.
    WHEN:  Layer 1.F evaluates the command using the canonical
           shlex.shlex(posix=True, punctuation_chars=True) tokenizer.
    THEN:  hook DENIES (rc=2) all 4 cases — punctuation_chars=True correctly
           splits unspaced separators that plain shlex.split would glue to
           a token.
    """
    assert HOOK_PATH.exists(), f"hook missing at {HOOK_PATH}"

    rc, _stdout, stderr = _run_hook_with_payload(HOOK_PATH, command)

    assert rc == expected_exit, (
        f"[{case}] expected exit {expected_exit}, got {rc}. "
        f"command={command!r}, stderr={stderr!r}"
    )
    assert STABLE_STDERR_TOKEN in stderr, (
        f"[{case}] expected stable stderr token "
        f"'{STABLE_STDERR_TOKEN}' in stderr, got stderr={stderr!r}"
    )
